#include <stdio.h>
int main() {
    int N, Q;
    scanf("%d %d", &N, &Q);
    int A[N];
    for (int i = 0; i < N; i++) {
        scanf("%d", &A[i]);
    }
    int prefixSum[N + 1];
    prefixSum[0] = 0;
    for (int i = 1; i <= N; i++) {
        prefixSum[i] = prefixSum[i - 1] ^ A[i - 1];
    }
    for (int i = 0; i < Q; i++) {
        int type, x, y;
        scanf("%d %d %d", &type, &x, &y);
        if (type == 1) {
            A[x - 1] = y;
            prefixSum[0] = 0;
            for (int j = 1; j <= N; j++) {
                prefixSum[j] = prefixSum[j - 1] ^ A[j - 1];
            }
        } else {
            int count = 0;
            for (int j = 1; j <= x; j++) {
                int xor = prefixSum[x] ^ prefixSum[j - 1];
                if (xor == y) {
                    count++;
                }
            }
            printf("%d\n", count);
        }
    }
    return 0;
}

