import java.util.Scanner;
public class Main {
    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        int N = sc.nextInt();
        int Q = sc.nextInt();
        int[] A = new int[N];
        for (int i = 0; i < N; i++) {
            A[i] = sc.nextInt();
        }
        int[] prefixSum = new int[N + 1];
        prefixSum[0] = 0;
        for (int i = 1; i <= N; i++) {
            prefixSum[i] = prefixSum[i - 1] ^ A[i - 1];
        }
        for (int i = 0; i < Q; i++) {
            int type = sc.nextInt();
            int x = sc.nextInt();
            int y = sc.nextInt();
            if (type == 1) {
                A[x - 1] = y;
                prefixSum[0] = 0;
                for (int j = 1; j <= N; j++) {
                    prefixSum[j] = prefixSum[j - 1] ^ A[j - 1];
                }
            } else {
                int count = 0;
                for (int j = 1; j <= x; j++) {
                    int xor = prefixSum[x] ^ prefixSum[j - 1];
                    if (xor == y) {
                        count++;
                    }
                }
                System.out.println(count);
            }
        }
    }
